from google_adk.agents import Agent
from google_adk.tools import Tool

class CodeExecutor(Tool):
    def execute(self, code: str) -> dict:
        # Sandbox execution
        result = sandbox_exec(code)
        return {'success': result.success, 'output': result.stdout}

class CodeGenerator(Agent):
    def __init__(self):
        super().__init__(
            model='gemini-1.5-pro',
            tools=[CodeExecutor()],
            instructions='Generate clean, safe Python code meeting requirements.'
        )

    async def generate_and_test(self, requirements: str):
        code = await self.run(f'Write Python code for: {requirements}')
        result = await self.tools[0].execute(code)
        return {'code': code, 'test_result': result}

import docker

class SecureSandbox(Tool):
    def __init__(self):
        self.client = docker.from_env()

    def execute(self, code: str, deps: list = None) -> dict:
        deps = deps or ['numpy==1.24.0']

        # Safety check
        if self._contains_dangerous_code(code):
            return {'success': False, 'error': 'Unsafe code detected'}

        container = self.client.containers.run(
            'python:3.11-slim',
            command=f'pip install {' '.join(deps)} && python -c "{code}"',
            detach=True,
            remove=True,
            mem_limit='256m'
        )
        result = container.wait()
        logs = container.logs().decode()
        return {'success': result['StatusCode'] == 0, 'output': logs}

