@vex_client.guardrail("session_state")
def protect_session_state(session_id: str, state_update: dict) -> dict:
    """Validate session state updates"""

    # Check state size limits
    if len(str(state_update)) > 100_000:
        raise Exception("Session state exceeds size limit")

    # Prevent credential accumulation
    credentials = vex_client.extract_credentials(state_update)
    if credentials:
        vex_client.log_security_event(session_id, "credentials_in_state", credentials)
        state_update = vex_client.sanitize_state(state_update)

    # Validate code versions
    if 'code_versions' in state_update:
        for version in state_update['code_versions']:
            vex_client.validate_code_syntax(version)

    return state_update

# Integrate with ADK session management
orchestrator.session_manager.state_update_callback = protect_session_state

@vex_client.guardrail("output_consistency")
def normalize_tool_response(tool_name: str, response: dict) -> dict:
    """Normalize tool outputs for consistent agent communication"""

    schema = {
        'CodeExecutor': {'success': bool, 'output': str, 'error': str | None},
        'TestValidator': {'passes': bool, 'coverage': float, 'errors': list},
        'CodeReviewer': {'safety_score': float, 'issues': list, 'approved': bool}
    }

    expected = schema.get(tool_name, {'result': str})
    normalized = vex_client.validate_and_normalize(response, expected)

    # Gemini consistency check
    if 'code' in normalized:
        vex_client.enforce_code_style(normalized['code'])

    return normalized

# Apply to all tools
for tool in orchestrator.tools:
    tool.post_execute_callback = normalize_tool_response
